Code.NativeIaC:
```bicep
// Bicep: AKS cluster with local accounts disabled
resource aks 'Microsoft.ContainerService/managedClusters@2024-02-01' = {
  name: '<example_resource_name>'
  location: resourceGroup().location
  properties: {
    disableLocalAccounts: true // CRITICAL: forces authentication through Entra ID
    aadProfile: {
      managed: true
      enableAzureRbac: true
    }
  }
}
```

Code.Terraform:
```hcl
# Terraform: AKS cluster with local accounts disabled
resource "azurerm_kubernetes_cluster" "<example_resource_name>" {
  name                  = "<example_resource_name>"
  location              = "<region>"
  resource_group_name   = "<example_resource_name>"
  dns_prefix            = "<example_resource_name>"
  local_account_disabled = true # CRITICAL: forces authentication through Entra ID

  azure_active_directory_role_based_access_control {
    azure_rbac_enabled = true
  }
}
```
